// One compact digest of everything the integration design needs.
const j=n=>{try{return $(n).first().json||{};}catch(e){return {};}};
const interesting=/buy|role|influen|stakeholder|persona|decision|network|level|seniorit/i;

const pipelines=(j('1. Deal pipelines').results||[]).map(p=>({pipeline:p.label,id:p.id,stages:(p.stages||[]).map(s=>s.label)}));

const propPick=res=>((res.results||[]).filter(p=>interesting.test(p.name+' '+(p.label||''))).map(p=>({name:p.name,label:p.label,type:p.type,options:(p.options||[]).slice(0,12).map(o=>o.label)})));
const contact_props_of_interest=propPick(j('2. Contact properties'));
const deal_props_of_interest=propPick(j('3. Deal properties'));

const companies=(j('4. Companies').results||[]).map(c=>({id:c.id,name:(c.properties||{}).name,domain:(c.properties||{}).domain}));

const compAssoc=o=>{const a=((o.associations||{}).companies||{}).results||[];return a.length?a[0].id:null;};
const contacts=(j('5. Contacts (sample)').results||[]).map(c=>{const p=c.properties||{};return {name:((p.firstname||'')+' '+(p.lastname||'')).trim(),jobtitle:p.jobtitle||null,hs_buying_role:p.hs_buying_role||null,company_id:compAssoc(c)};});

const deals=(j('6. Deals (sample)').results||[]).map(d=>{const p=d.properties||{};return {name:p.dealname,amount:p.amount,stage:p.dealstage,pipeline:p.pipeline,close:p.closedate,company_id:compAssoc(d)};});

return [{json:{pipelines,contact_props_of_interest,deal_props_of_interest,companies,contacts,deals}}];
